INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Proverbs', 1, 'kids', 1, 'What is the beginning of knowledge according to Proverbs 1?', 'The fear of the LORD', 'Reading many books', 'Listening to your teacher', 'Going to school', 'a', 'Proverbs 1:7 says, "The fear of the LORD is the beginning of knowledge."'),
('Proverbs', 1, 'kids', 2, 'Who wrote the book of Proverbs according to chapter 1?', 'David', 'Moses', 'Solomon', 'Isaiah', 'a', 'Proverbs 1:1 says, "The proverbs of Solomon the son of David, king of Israel."'),
('Proverbs', 1, 'kids', 3, 'What does Proverbs 1 say a child should listen to?', 'The instruction of a father', 'The songs of the birds', 'The laws of the king', 'The wisdom of strangers', 'a', 'Proverbs 1:8 says, "Hear, the instruction of thy father."'),
('Proverbs', 1, 'teens', 1, 'What does Proverbs 1:7 say fools despise?', 'Wisdom and instruction', 'Their neighbours', 'Hard work', 'The king', 'a', 'Proverbs 1:7 says, "but fools despise wisdom and instruction."'),
('Proverbs', 1, 'teens', 2, 'In Proverbs 1, what does wisdom do in the streets?', 'She weeps and mourns', 'She uttereth her voice', 'She builds a house', 'She plants a garden', 'a', 'Proverbs 1:20 says, "Wisdom crieth without; she uttereth her voice in the streets."'),
('Proverbs', 1, 'teens', 3, 'What does Proverbs 1 warn against joining?', 'Sinners who lay in wait for blood', 'Foreign armies', 'Strange religions', 'Merchants on the road', 'a', 'Proverbs 1:10-11 warns, "if sinners entice thee...they lay wait for blood."'),
('Proverbs', 1, 'teens', 4, 'What happens to those who reject wisdom''s call according to Proverbs 1?', 'They will prosper in their own way', 'They will eat the fruit of their own way', 'They will find another teacher', 'They will be given a second chance', 'a', 'Proverbs 1:31 says, "Therefore shall they eat of the fruit of their own way."'),
('Proverbs', 1, 'teens', 5, 'What will the LORD pour out when people seek Him after rejecting wisdom?', 'His Spirit', 'His anger', 'His judgement', 'His silence', 'a', 'Proverbs 1:23 says, "I will pour out my spirit unto you, I will make known my words unto you."'),
('Proverbs', 1, 'adults', 1, 'What is the stated purpose of the proverbs in Proverbs 1:2-4?', 'To entertain the people of Israel', 'To know wisdom and instruction, to perceive words of understanding', 'To record the history of Solomon', 'To teach the law of Moses', 'a', 'Proverbs 1:2 states, "To know wisdom and instruction; to perceive the words of understanding."'),
('Proverbs', 1, 'adults', 2, 'What instruction regarding ornamental grace does Proverbs 1:9 give?', 'Wisdom is a crown for the head', 'The instruction of parents shall be an ornament of grace unto thy head', 'A soft answer turns away wrath', 'The fear of the LORD adds years to life', 'a', 'Proverbs 1:9 says, "For they shall be an ornament of grace unto thy head, and chains about thy neck."'),
('Proverbs', 1, 'adults', 3, 'How does Wisdom react when calamity falls on those who rejected her according to Proverbs 1:26?', 'She mourns with them', 'She will laugh at their calamity and mock when their fear cometh', 'She offers them another chance', 'She intercedes for them', 'a', 'Proverbs 1:26 says, "I also will laugh at your calamity; I will mock when your fear cometh."'),
('Proverbs', 1, 'adults', 4, 'What three things does Proverbs 1:4 say the proverbs give to the simple?', 'Subtilty, and to the young man knowledge and discretion', 'Wealth, honour, and long life', 'Peace, joy, and understanding', 'Faith, hope, and love', 'a', 'Proverbs 1:4 says, "To give subtilty to the simple, to the young man knowledge and discretion."'),
('Proverbs', 1, 'adults', 5, 'In Proverbs 1:17, what illustration does Solomon use about setting a trap?', 'A bird is not caught if it sees the net spread', 'A fish sees the bait and avoids the hook', 'A deer sees the snare and leaps away', 'A lion sees the hunter and hides', 'a', 'Proverbs 1:17 says, "Surely in vain the net is spread in the sight of any bird."'),
('Proverbs', 1, 'adults', 6, 'What does Proverbs 1:33 promise to the one who hearkens to wisdom?', 'He shall dwell safely and be quiet from fear of evil', 'He shall have silver and gold', 'He shall rule over nations', 'He shall live a thousand years', 'a', 'Proverbs 1:33 says, "But whoso hearkeneth unto me shall dwell safely, and shall be quiet from fear of evil."'),
('Proverbs', 1, 'adults', 7, 'What does Proverbs 1:6 indicate these proverbs will help a wise man understand?', 'A proverb, and the interpretation; the words of the wise, and their dark sayings', 'The laws of the king', 'The paths of the righteous', 'The prophecies of the prophets', 'a', 'Proverbs 1:6 says, "To understand a proverb, and the interpretation; the words of the wise, and their dark sayings."'),
('Proverbs', 1, 'adults', 8, 'In Proverbs 1:28-29, why will wisdom not answer when sinners call upon her?', 'Because they hated knowledge and did not choose the fear of the LORD', 'Because she is busy with the righteous', 'Because God has sealed her lips', 'Because the time for mercy is past forever', 'a', 'Proverbs 1:29 says, "For that they hated knowledge, and did not choose the fear of the LORD."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Proverbs', 2, 'kids', 1, 'Where does wisdom come from according to Proverbs 2?', 'From the LORD', 'From teachers', 'From books', 'From experience', 'a', 'Proverbs 2:6 says, "For the LORD giveth wisdom: out of his mouth cometh knowledge and understanding."'),
('Proverbs', 2, 'kids', 2, 'What does Proverbs 2 say will protect you like a shield?', 'God''s wisdom', 'A strong army', 'A city wall', 'Your father''s house', 'a', 'Proverbs 2:7 says God is "a buckler to them that walk uprightly."'),
('Proverbs', 2, 'kids', 3, 'What kind of paths does wisdom help you understand according to Proverbs 2?', 'Every good path', 'The paths to the city', 'The paths of kings', 'Mountain paths', 'a', 'Proverbs 2:9 says wisdom will help you understand "every good path."'),
('Proverbs', 2, 'teens', 1, 'What must a person do to find knowledge of God according to Proverbs 2:3-4?', 'Cry after wisdom and search for her as silver', 'Offer many sacrifices', 'Travel to Jerusalem', 'Ask wise elders', 'a', 'Proverbs 2:3-4 says to "cry after knowledge...and searchest for her as for hid treasures."'),
('Proverbs', 2, 'teens', 2, 'What does Proverbs 2 say wisdom will deliver you from?', 'The way of the evil man and the strange woman', 'Poverty and sickness', 'Enemies in battle', 'Hunger and thirst', 'a', 'Proverbs 2:12 says wisdom will deliver you "from the way of the evil man."'),
('Proverbs', 2, 'teens', 3, 'How is the strange woman''s house described in Proverbs 2:18?', 'Her house inclineth unto death', 'Her house is full of riches', 'Her house is built on a rock', 'Her house stands near the temple', 'a', 'Proverbs 2:18 says, "For her house inclineth unto death, and her paths unto the dead."'),
('Proverbs', 2, 'teens', 4, 'What does Proverbs 2:20 say the wise person will do?', 'Walk in the way of good men', 'Avoid all strangers', 'Seek silver and gold', 'Dwell in the mountains', 'a', 'Proverbs 2:20 says, "That thou mayest walk in the way of good men, and keep the paths of the righteous."'),
('Proverbs', 2, 'teens', 5, 'What will the upright dwell in according to Proverbs 2:21?', 'The land', 'The king''s palace', 'The temple courts', 'The mountains', 'a', 'Proverbs 2:21 says, "For the upright shall dwell in the land, and the perfect shall remain in it."'),
('Proverbs', 2, 'adults', 1, 'What two qualities does Proverbs 2:7 say God lays up for the righteous?', 'Sound wisdom and a buckler', 'Silver and gold', 'Long life and peace', 'Honour and strength', 'a', 'Proverbs 2:7 says, "He layeth up sound wisdom for the righteous: he is a buckler to them that walk uprightly."'),
('Proverbs', 2, 'adults', 2, 'What does Proverbs 2:5 say seeking wisdom leads to?', 'Understanding the fear of the LORD and finding the knowledge of God', 'Wealth and prosperity', 'Fame among the nations', 'Victory over enemies', 'a', 'Proverbs 2:5 says, "Then shalt thou understand the fear of the LORD, and find the knowledge of God."'),
('Proverbs', 2, 'adults', 3, 'How does Proverbs 2:16-17 describe the strange woman''s spiritual condition?', 'She forsaketh the guide of her youth and forgetteth the covenant of her God', 'She never knew the LORD', 'She worships idols openly', 'She is a stranger from another nation', 'a', 'Proverbs 2:17 says she "forsaketh the guide of her youth, and forgetteth the covenant of her God."'),
('Proverbs', 2, 'adults', 4, 'What does Proverbs 2:11 say will preserve and keep the seeker of wisdom?', 'Discretion and understanding', 'Prayer and fasting', 'Parents and teachers', 'Laws and statutes', 'a', 'Proverbs 2:11 says, "Discretion shall preserve thee, understanding shall keep thee."'),
('Proverbs', 2, 'adults', 5, 'What is the fate of the wicked in Proverbs 2:22?', 'The wicked shall be cut off from the earth', 'The wicked shall wander in the wilderness', 'The wicked shall lose their wealth', 'The wicked shall be enslaved', 'a', 'Proverbs 2:22 says, "But the wicked shall be cut off from the earth, and the transgressors shall be rooted out of it."'),
('Proverbs', 2, 'adults', 6, 'What does Proverbs 2:8 say God preserveth?', 'The paths of judgment and the way of his saints', 'The words of the prophets', 'The boundaries of Israel', 'The records of the righteous', 'a', 'Proverbs 2:8 says, "He keepeth the paths of judgment, and preserveth the way of his saints."'),
('Proverbs', 2, 'adults', 7, 'What condition is stated in Proverbs 2:1-2 for the benefits of wisdom to flow?', 'If thou wilt receive words and hide commandments, inclining thine ear unto wisdom', 'If thou offerest sacrifices daily', 'If thou keepest the Sabbath', 'If thou teachest others', 'a', 'Proverbs 2:1-2 says, "If thou wilt receive my words, and hide my commandments with thee; so that thou incline thine ear unto wisdom."'),
('Proverbs', 2, 'adults', 8, 'What does Proverbs 2:10 say will happen when wisdom enters the heart?', 'Knowledge will be pleasant unto thy soul', 'Riches will follow thee', 'The LORD will speak to thee', 'Enemies will flee from thee', 'a', 'Proverbs 2:10 says, "When wisdom entereth into thine heart, and knowledge is pleasant unto thy soul."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Proverbs', 3, 'kids', 1, 'What does Proverbs 3:5 say we should trust with all our heart?', 'The LORD', 'Our parents', 'Our own understanding', 'Wise teachers', 'a', 'Proverbs 3:5 says, "Trust in the LORD with all thine heart."'),
('Proverbs', 3, 'kids', 2, 'What does Proverbs 3:6 say will happen if we acknowledge God in all our ways?', 'He shall direct our paths', 'He shall give us riches', 'He shall send angels', 'He shall give us long life', 'a', 'Proverbs 3:6 says, "In all thy ways acknowledge him, and he shall direct thy paths."'),
('Proverbs', 3, 'kids', 3, 'What should we honour the LORD with according to Proverbs 3?', 'Our substance and firstfruits', 'Songs and dancing', 'Prayers and fasting', 'Our time and talent', 'a', 'Proverbs 3:9 says, "Honour the LORD with thy substance, and with the firstfruits of all thine increase."'),
('Proverbs', 3, 'teens', 1, 'What does Proverbs 3:5 warn us NOT to lean on?', 'Our own understanding', 'The strength of others', 'The wisdom of the world', 'The riches of men', 'a', 'Proverbs 3:5 says, "lean not unto thine own understanding."'),
('Proverbs', 3, 'teens', 2, 'What does Proverbs 3:11-12 say about the LORD''s chastening?', 'Do not despise it, for the LORD corrects those He loves', 'Pray that it ends quickly', 'Only the wicked are chastened', 'It means God has forgotten you', 'a', 'Proverbs 3:11-12 says, "despise not the chastening of the LORD...for whom the LORD loveth he correcteth."'),
('Proverbs', 3, 'teens', 3, 'What is wisdom''s right hand said to hold in Proverbs 3:16?', 'Length of days', 'Riches and honour', 'Understanding', 'Peace and safety', 'a', 'Proverbs 3:16 says, "Length of days is in her right hand; and in her left hand riches and honour."'),
('Proverbs', 3, 'teens', 4, 'What does Proverbs 3:27 instruct about doing good?', 'Withhold not good from them to whom it is due', 'Do good only to your family', 'Wait for the right moment', 'Do good secretly', 'a', 'Proverbs 3:27 says, "Withhold not good from them to whom it is due, when it is in the power of thine hand to do it."'),
('Proverbs', 3, 'teens', 5, 'What does Proverbs 3:34 say God does to the scorners but gives to the lowly?', 'He scorneth the scorners but giveth grace unto the lowly', 'He ignores the scorners but blesses the lowly with wealth', 'He punishes the scorners but saves the lowly', 'He silences the scorners but speaks to the lowly', 'a', 'Proverbs 3:34 says, "Surely he scorneth the scorners: but he giveth grace unto the lowly."'),
('Proverbs', 3, 'adults', 1, 'What does Proverbs 3:3 instruct about mercy and truth?', 'Bind them about thy neck, write them upon the table of thine heart', 'Teach them to thy children daily', 'Seek them in the house of the LORD', 'Store them in thy heart and mind', 'a', 'Proverbs 3:3 says, "Let not mercy and truth forsake thee: bind them about thy neck; write them upon the table of thine heart."'),
('Proverbs', 3, 'adults', 2, 'What does Proverbs 3:7 warn against?', 'Being wise in thine own eyes; fear the LORD and depart from evil', 'Trusting in wealth', 'Following strange gods', 'Despising the poor', 'a', 'Proverbs 3:7 says, "Be not wise in thine own eyes: fear the LORD, and depart from evil."'),
('Proverbs', 3, 'adults', 3, 'What is the reward promised in Proverbs 3:10 for honouring God with firstfruits?', 'Barns filled with plenty and vats overflowing with new wine', 'A long life and peaceful death', 'Victory over enemies', 'Favour with the king', 'a', 'Proverbs 3:10 says, "So shall thy barns be filled with plenty, and thy presses shall burst out with new wine."'),
('Proverbs', 3, 'adults', 4, 'How is wisdom described in Proverbs 3:17-18?', 'Her ways are ways of pleasantness, and all her paths are peace; she is a tree of life', 'She is a lamp unto the feet', 'She is more precious than rubies alone', 'She stands at the city gate', 'a', 'Proverbs 3:17-18 says, "Her ways are ways of pleasantness, and all her paths are peace. She is a tree of life to them that lay hold upon her."'),
('Proverbs', 3, 'adults', 5, 'What does Proverbs 3:19-20 say wisdom was used for?', 'The LORD founded the earth by wisdom and established the heavens by understanding', 'Writing the law of Moses', 'Building the temple', 'Dividing the Red Sea', 'a', 'Proverbs 3:19 says, "The LORD by wisdom hath founded the earth; by understanding hath he established the heavens."'),
('Proverbs', 3, 'adults', 6, 'What does Proverbs 3:30 warn against?', 'Striving with a man without cause when he hath done thee no harm', 'Making promises you cannot keep', 'Lending money to the poor', 'Boasting of tomorrow', 'a', 'Proverbs 3:30 says, "Strive not with a man without cause, if he have done thee no harm."'),
('Proverbs', 3, 'adults', 7, 'What blessings does Proverbs 3:24 promise to the one who keeps wisdom?', 'When thou liest down thou shalt not be afraid; thy sleep shall be sweet', 'Wealth and long life', 'Victory and honour', 'Health and strength', 'a', 'Proverbs 3:24 says, "When thou liest down, thou shalt not be afraid: yea, thou shalt lie down, and thy sleep shall be sweet."'),
('Proverbs', 3, 'adults', 8, 'What does Proverbs 3:13 declare about the man who finds wisdom?', 'Happy is the man that findeth wisdom, and the man that getteth understanding', 'Blessed is the king who seeks counsel', 'Rich is the man who fears the LORD', 'Wise is the man who reads the law', 'a', 'Proverbs 3:13 says, "Happy is the man that findeth wisdom, and the man that getteth understanding."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Proverbs', 4, 'kids', 1, 'What does Proverbs 4 say is the principal thing we should get?', 'Wisdom', 'Gold', 'Friends', 'Strength', 'a', 'Proverbs 4:7 says, "Wisdom is the principal thing; therefore get wisdom."'),
('Proverbs', 4, 'kids', 2, 'What does the path of the just shine like in Proverbs 4?', 'The shining light that shineth more and more unto the perfect day', 'A candle in the dark', 'The morning star', 'The sun at noon', 'a', 'Proverbs 4:18 says, "But the path of the just is as the shining light, that shineth more and more unto the perfect day."'),
('Proverbs', 4, 'kids', 3, 'What does Proverbs 4:23 tell us to keep above all things?', 'Our heart', 'Our words', 'Our eyes', 'Our feet', 'a', 'Proverbs 4:23 says, "Keep thy heart with all diligence; for out of it are the issues of life."'),
('Proverbs', 4, 'teens', 1, 'How did Solomon''s father teach him about wisdom according to Proverbs 4?', 'He instructed him and said, "Get wisdom, get understanding"', 'He sent him to school', 'He gave him books to read', 'He showed him by example only', 'a', 'Proverbs 4:4-5 says his father instructed, "Get wisdom, get understanding: forget it not."'),
('Proverbs', 4, 'teens', 2, 'What will wisdom do for you if you embrace her according to Proverbs 4:8?', 'She shall promote thee and bring thee to honour', 'She shall give thee silver', 'She shall protect thee in battle', 'She shall make thee a king', 'a', 'Proverbs 4:8 says, "Exalt her, and she shall promote thee: she shall bring thee to honour, when thou dost embrace her."'),
('Proverbs', 4, 'teens', 3, 'What does Proverbs 4:14-15 say about the path of the wicked?', 'Enter not into it, avoid it, pass not by it, turn from it', 'Walk carefully through it', 'Only visit it to warn others', 'Study it to understand evil', 'a', 'Proverbs 4:14-15 says, "Enter not into the path of the wicked...Avoid it, pass not by it, turn from it."'),
('Proverbs', 4, 'teens', 4, 'What does Proverbs 4:19 say about the way of the wicked?', 'It is as darkness, they know not at what they stumble', 'It leads to poverty and shame', 'It ends in sudden destruction', 'It is wide and easy to travel', 'a', 'Proverbs 4:19 says, "The way of the wicked is as darkness: they know not at what they stumble."'),
('Proverbs', 4, 'teens', 5, 'What four body parts does Proverbs 4:24-27 give instructions about?', 'Mouth, eyes, eyelids, and feet', 'Hands, feet, ears, and eyes', 'Heart, mind, tongue, and hands', 'Lips, ears, hands, and knees', 'a', 'Proverbs 4:24-27 addresses the mouth (4:24), eyes (4:25), eyelids (4:25), and feet (4:26-27).'),
('Proverbs', 4, 'adults', 1, 'What does Proverbs 4:7 say about getting wisdom even at cost?', 'With all thy getting get understanding', 'Sell all thou hast to buy it', 'Seek it above silver and gold', 'Pay any price for instruction', 'a', 'Proverbs 4:7 says, "Wisdom is the principal thing; therefore get wisdom: and with all thy getting get understanding."'),
('Proverbs', 4, 'adults', 2, 'What will wisdom place on your head according to Proverbs 4:9?', 'An ornament of grace and a crown of glory', 'A garland of flowers', 'The diadem of kings', 'A crown of righteousness', 'a', 'Proverbs 4:9 says, "She shall give to thine head an ornament of grace: a crown of glory shall she deliver to thee."'),
('Proverbs', 4, 'adults', 3, 'What does Proverbs 4:10 promise to the one who receives wisdom''s sayings?', 'The years of thy life shall be many', 'Thy barns shall be filled', 'Thy enemies shall flee', 'Thy name shall be remembered', 'a', 'Proverbs 4:10 says, "Hear, O my son, and receive my sayings; and the years of thy life shall be many."'),
('Proverbs', 4, 'adults', 4, 'How does Proverbs 4:16-17 describe the wicked man''s need to do evil?', 'They sleep not except they have done mischief; they eat the bread of wickedness', 'They wander seeking someone to harm', 'They plot evil by day and execute it by night', 'They love violence more than peace', 'a', 'Proverbs 4:16-17 says, "For they sleep not, except they have done mischief...For they eat the bread of wickedness."'),
('Proverbs', 4, 'adults', 5, 'What does Proverbs 4:20-22 say about the father''s words?', 'They are life unto those that find them and health to all their flesh', 'They are sweeter than honey', 'They are sharper than a two-edged sword', 'They are more precious than rubies', 'a', 'Proverbs 4:22 says, "For they are life unto those that find them, and health to all their flesh."'),
('Proverbs', 4, 'adults', 6, 'What does "out of it are the issues of life" mean in Proverbs 4:23?', 'The heart is the source of one''s entire life direction and character', 'The heart pumps blood to keep one alive', 'Emotions come from the heart', 'Life''s problems come from a troubled heart', 'a', 'Proverbs 4:23 says "keep thy heart...for out of it are the issues of life" — the heart determines life''s course.'),
('Proverbs', 4, 'adults', 7, 'What specific speech instruction is given in Proverbs 4:24?', 'Put away from thee a froward mouth, and perverse lips put far from thee', 'Speak softly to your enemies', 'Say only what is true', 'Let your words be few', 'a', 'Proverbs 4:24 says, "Put away from thee a froward mouth, and perverse lips put far from thee."'),
('Proverbs', 4, 'adults', 8, 'What does Proverbs 4:26 instruct about ordering one''s ways?', 'Ponder the path of thy feet, and let all thy ways be established', 'Walk only on known paths', 'Follow the way of the righteous man', 'Let your steps be guided by prayer', 'a', 'Proverbs 4:26 says, "Ponder the path of thy feet, and let all thy ways be established."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Proverbs', 5, 'kids', 1, 'What does Proverbs 5 tell a young man to rejoice with?', 'The wife of his youth', 'His friends and family', 'The blessings of God', 'His father''s house', 'a', 'Proverbs 5:18 says, "rejoice with the wife of thy youth."'),
('Proverbs', 5, 'kids', 2, 'What does Proverbs 5 warn that a strange woman''s lips drop like?', 'Honeycomb', 'Poison', 'Dew', 'Bittersweet fruit', 'a', 'Proverbs 5:3 says, "For the lips of a strange woman drop as an honeycomb."'),
('Proverbs', 5, 'kids', 3, 'What does Proverbs 5:21 say the LORD does?', 'His ways are before the eyes of the LORD', 'He watches over the righteous', 'He blesses those who obey', 'He guides the feet of the just', 'a', 'Proverbs 5:21 says, "For the ways of man are before the eyes of the LORD."'),
('Proverbs', 5, 'teens', 1, 'What is the end of the strange woman''s lips and feet according to Proverbs 5:3-5?', 'Bitter as wormwood, her feet go down to death', 'Sweet but costly', 'Pleasing but fleeting', 'Lovely but deadly slow', 'a', 'Proverbs 5:4-5 says, "But her end is bitter as wormwood...Her feet go down to death."'),
('Proverbs', 5, 'teens', 2, 'What does Proverbs 5:8 counsel concerning the strange woman?', 'Remove thy way far from her and come not nigh the door of her house', 'Warn her of her sin', 'Pray for her repentance', 'Report her to the elders', 'a', 'Proverbs 5:8 says, "Remove thy way far from her, and come not nigh the door of her house."'),
('Proverbs', 5, 'teens', 3, 'What regret does the foolish man express in Proverbs 5:12-13?', 'How have I hated instruction and my heart despised reproof', 'Why did I not listen to my father', 'I have wasted all my silver', 'I have dishonoured my family', 'a', 'Proverbs 5:12-13 says, "How have I hated instruction, and my heart despised reproof; and have not obeyed the voice of my teachers."'),
('Proverbs', 5, 'teens', 4, 'How does Proverbs 5:15-16 use water imagery to teach faithfulness in marriage?', 'Drink waters from thine own cistern, not let thy fountains be dispersed abroad', 'Build your house on the rock not the sand', 'A flowing stream brings life to the desert', 'Still waters reflect what is in the heart', 'a', 'Proverbs 5:15-16 says, "Drink waters out of thine own cistern...Let thy fountains be dispersed abroad."'),
('Proverbs', 5, 'teens', 5, 'What fate awaits the wicked man who follows the strange woman according to Proverbs 5:22?', 'His own iniquities shall take the wicked himself', 'He shall lose his inheritance', 'He shall be driven from the city', 'He shall be put to shame before all', 'a', 'Proverbs 5:22 says, "His own iniquities shall take the wicked himself, and he shall be holden with the cords of his sins."'),
('Proverbs', 5, 'adults', 1, 'What does Proverbs 5:6 say about the strange woman''s way of life?', 'Her ways are moveable, that thou canst not know them', 'She walks the path of destruction openly', 'She plans every step to ensnare', 'She pretends righteousness to deceive', 'a', 'Proverbs 5:6 says, "Her ways are moveable, that thou canst not know them."'),
('Proverbs', 5, 'adults', 2, 'What shame does Proverbs 5:9-10 warn will come from following the strange woman?', 'Thine honour given unto others and thy years unto the cruel', 'Loss of position and wealth', 'Exile from the nation', 'Sickness and poverty', 'a', 'Proverbs 5:9-10 says, "Lest thou give thine honour unto others, and thy years unto the cruel...and thy labours be in the house of a stranger."'),
('Proverbs', 5, 'adults', 3, 'What does Proverbs 5:11 say will happen at the end of a life of immorality?', 'Thou mournest at the last when thy flesh and body are consumed', 'You will seek wisdom but not find it', 'Your children will be ashamed', 'You will lose all your friends', 'a', 'Proverbs 5:11 says, "And thou mourn at the last, when thy flesh and thy body are consumed."'),
('Proverbs', 5, 'adults', 4, 'How does Proverbs 5:18-19 describe the blessing of a faithful wife?', 'As a loving hind and pleasant roe, let her breasts satisfy thee at all times', 'As a tower of strength and comfort', 'As a fruitful vine and gentle stream', 'As the morning star and evening rest', 'a', 'Proverbs 5:19 says, "Let her be as the loving hind and pleasant roe...let her breasts satisfy thee at all times."'),
('Proverbs', 5, 'adults', 5, 'What does Proverbs 5:20 use as a rhetorical question to urge faithfulness?', 'Why wilt thou be ravished with a strange woman and embrace the bosom of a stranger', 'Why wouldst thou leave the path of righteousness', 'Why dost thou despise the wife of thy youth', 'Why art thou drawn to vanity and emptiness', 'a', 'Proverbs 5:20 says, "And why wilt thou, my son, be ravished with a strange woman, and embrace the bosom of a stranger?"'),
('Proverbs', 5, 'adults', 6, 'What does Proverbs 5:22 teach about the self-defeating nature of sin?', 'The cords of a man''s sins hold him fast; he is holden with the cords of his sins', 'Sin eventually leads to open shame', 'The wicked will be punished by God alone', 'Evil deeds come back as a snare', 'a', 'Proverbs 5:22 says, "his own iniquities shall take the wicked himself, and he shall be holden with the cords of his sins."'),
('Proverbs', 5, 'adults', 7, 'What does the image of "cistern" and "well" in Proverbs 5:15 symbolise?', 'One''s own wife as the lawful source of marital intimacy', 'The word of God as a source of life', 'The temple as the dwelling of the LORD', 'A city''s supply of fresh water', 'a', 'Proverbs 5:15 says, "Drink waters out of thine own cistern, and running waters out of thine own well" — referring to one''s own wife.'),
('Proverbs', 5, 'adults', 8, 'What is the concluding fate of the man who ignores instruction according to Proverbs 5:23?', 'He shall die without instruction and go astray through his great folly', 'He shall be cut off from his people', 'He shall wander in the wilderness', 'He shall be given over to his enemies', 'a', 'Proverbs 5:23 says, "He shall die without instruction; and in the greatness of his folly he shall go astray."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Proverbs', 6, 'kids', 1, 'What small creature does Proverbs 6 tell the lazy person to learn from?', 'The ant', 'The bee', 'The sparrow', 'The ox', 'a', 'Proverbs 6:6 says, "Go to the ant, thou sluggard; consider her ways, and be wise."'),
('Proverbs', 6, 'kids', 2, 'How many things does the LORD hate according to Proverbs 6?', 'Six, yes seven', 'Three', 'Ten', 'Five', 'a', 'Proverbs 6:16 says, "These six things doth the LORD hate: yea, seven are an abomination unto him."'),
('Proverbs', 6, 'kids', 3, 'What does Proverbs 6 say a naughty person does with their fingers?', 'He teacheth with his fingers', 'He points and winks with mischief', 'He hides what he has stolen', 'He writes lies on tablets', 'a', 'Proverbs 6:13 says, "He winketh with his eyes, he speaketh with his feet, he teacheth with his fingers."'),
('Proverbs', 6, 'teens', 1, 'What does Proverbs 6:1-3 warn about becoming surety (co-signing a pledge) for another?', 'Thou art snared with the words of thy mouth; deliver thyself', 'It is a noble act of friendship', 'It brings blessing if the friend is righteous', 'The LORD will reward thee for it', 'a', 'Proverbs 6:2-3 says, "Thou art snared with the words of thy mouth...deliver thyself."'),
('Proverbs', 6, 'teens', 2, 'What does the ant do without having a guide, overseer, or ruler according to Proverbs 6:7-8?', 'Provideth her meat in the summer and gathereth food in the harvest', 'Builds her house and protects her young', 'Follows the queen in all things', 'Seeks wisdom from older ants', 'a', 'Proverbs 6:7-8 says the ant, "provideth her meat in the summer, and gathereth her food in the harvest."'),
('Proverbs', 6, 'teens', 3, 'What first item in the seven abominations does God hate in Proverbs 6:17?', 'A proud look', 'A lying tongue', 'Hands that shed blood', 'A froward heart', 'a', 'Proverbs 6:17 lists first "A proud look" among the seven things the LORD hates.'),
('Proverbs', 6, 'teens', 4, 'What does Proverbs 6:20-22 say about a father''s commandments when you walk and when you sleep?', 'They shall lead thee, keep thee, and talk with thee', 'They shall be a lamp to your path', 'They shall comfort thee in trouble', 'They shall make thee wise among thy peers', 'a', 'Proverbs 6:22 says, "When thou goest, it shall lead thee; when thou sleepest, it shall keep thee; and when thou awakest, it shall talk with thee."'),
('Proverbs', 6, 'teens', 5, 'What does Proverbs 6:26 warn about the cost of following an immoral woman?', 'By means of a whorish woman a man is brought to a piece of bread', 'She will rob thee of thy silver', 'She leads men to ruin their health', 'She brings shame upon a man''s family', 'a', 'Proverbs 6:26 says, "For by means of a whorish woman a man is brought to a piece of bread."'),
('Proverbs', 6, 'adults', 1, 'What four descriptors does Proverbs 6:12-13 use for a naughty and wicked person?', 'Froward mouth, winking eyes, speaking feet, teaching fingers', 'Proud heart, lying lips, swift feet, false witness', 'Haughty eyes, lying tongue, wicked heart, discord sower', 'Idle hands, wandering eyes, crooked path, false scales', 'a', 'Proverbs 6:12-13 describes: "A naughty person...walketh with a froward mouth. He winketh with his eyes, he speaketh with his feet, he teacheth with his fingers."'),
('Proverbs', 6, 'adults', 2, 'What does Proverbs 6:15 say will happen suddenly to the wicked person who sows discord?', 'He shall be broken without remedy', 'He shall fall into poverty', 'He shall be cast out of the city', 'He shall be put to shame', 'a', 'Proverbs 6:15 says, "Therefore shall his calamity come suddenly; suddenly shall he be broken without remedy."'),
('Proverbs', 6, 'adults', 3, 'What is the seventh abomination listed in Proverbs 6:19?', 'He that soweth discord among brethren', 'A false witness that speaketh lies', 'Feet that be swift in running to mischief', 'A heart that deviseth wicked imaginations', 'a', 'Proverbs 6:19 says the seventh abomination is "he that soweth discord among brethren."'),
('Proverbs', 6, 'adults', 4, 'How does Proverbs 6:23 describe the commandment and the law of a godly father?', 'The commandment is a lamp and the law is light, and reproofs of instruction are the way of life', 'They are sweeter than honey and more precious than gold', 'They are the foundation of wisdom and the path of peace', 'They are arrows in the hand of a warrior', 'a', 'Proverbs 6:23 says, "For the commandment is a lamp; and the law is light; and reproofs of instruction are the way of life."'),
('Proverbs', 6, 'adults', 5, 'What does Proverbs 6:30-31 say distinguishes theft out of hunger from adultery?', 'A thief may be forgiven when caught but the adulterer faces wounds and dishonour', 'Theft is punishable by law but adultery is a private sin', 'Theft harms property but adultery harms no one', 'A thief can make restitution but adultery has no remedy', 'a', 'Proverbs 6:30-32 notes a thief is not despised when hungry but the adulterer destroys his own soul and gets wounds and dishonour.'),
('Proverbs', 6, 'adults', 6, 'What does Proverbs 6:34-35 say about the jealousy of a wronged husband?', 'His jealousy will not spare in the day of vengeance; he will not accept any ransom', 'He will seek revenge through the elders', 'He will demand full restitution', 'He will challenge the man to a public confrontation', 'a', 'Proverbs 6:34-35 says, "For jealousy is the rage of a man...He will not regard any ransom."'),
('Proverbs', 6, 'adults', 7, 'What does the ant''s behaviour in Proverbs 6:6-8 teach about planning for the future?', 'Diligent preparation in season prevents poverty without needing external compulsion', 'Follow a leader who sets the example', 'Work only when the reward is clear', 'Community effort achieves more than individual work', 'a', 'The ant "provideth her meat in the summer" without overseer (Proverbs 6:7-8), teaching self-motivated diligence.'),
('Proverbs', 6, 'adults', 8, 'What does Proverbs 6:9-11 warn will overtake the sluggard?', 'Poverty shall come as one that travelleth and want as an armed man', 'Shame before his neighbours', 'Hunger and sickness', 'Loss of his inheritance', 'a', 'Proverbs 6:11 says, "So shall thy poverty come as one that travelleth, and thy want as an armed man."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Proverbs', 7, 'kids', 1, 'What does Proverbs 7 say to call wisdom?', 'Call wisdom thy sister', 'Call wisdom thy guide', 'Call wisdom thy treasure', 'Call wisdom thy mother', 'a', 'Proverbs 7:4 says, "Say unto wisdom, Thou art my sister."'),
('Proverbs', 7, 'kids', 2, 'What animal is the foolish young man compared to in Proverbs 7?', 'An ox going to slaughter', 'A sheep gone astray', 'A dog returning to his vomit', 'A bird caught in a snare', 'a', 'Proverbs 7:22 says he goes "as an ox goeth to the slaughter."'),
('Proverbs', 7, 'kids', 3, 'From where did Solomon observe the foolish young man in Proverbs 7?', 'Through a window of his house', 'From the city gate', 'From the top of a hill', 'From a hiding place in the street', 'a', 'Proverbs 7:6 says, "For at the window of my house I looked through my casement."'),
('Proverbs', 7, 'teens', 1, 'At what time of day did the young man approach the strange woman''s house according to Proverbs 7?', 'In the twilight, in the evening, in the black and dark night', 'At the break of dawn', 'In the heat of the midday sun', 'At the busy noon hour', 'a', 'Proverbs 7:9 says, "In the twilight, in the evening, in the black and dark night."'),
('Proverbs', 7, 'teens', 2, 'How does the strange woman dress in Proverbs 7:10?', 'With the attire of an harlot and subtil of heart', 'In fine linen and jewels', 'In the robes of a widow', 'In the garments of a merchant', 'a', 'Proverbs 7:10 says she meets him "with the attire of an harlot, and subtil of heart."'),
('Proverbs', 7, 'teens', 3, 'What excuse does the strange woman give for her husband''s absence in Proverbs 7:19-20?', 'The goodman is gone on a long journey and will not come home till the day appointed', 'He is away at war', 'He is trading in a distant city', 'He is visiting the king', 'a', 'Proverbs 7:19-20 says, "For the goodman is not at home...he is gone a long journey."'),
('Proverbs', 7, 'teens', 4, 'What does Proverbs 7:26 say about the many victims of the strange woman?', 'She hath cast down many wounded; yea, many strong men have been slain by her', 'She has deceived the simple only', 'She traps only the foolish young', 'She has caused sorrow to many families', 'a', 'Proverbs 7:26 says, "For she hath cast down many wounded: yea, many strong men have been slain by her."'),
('Proverbs', 7, 'teens', 5, 'Where does the strange woman''s house lead according to Proverbs 7:27?', 'Her house is the way to hell, going down to the chambers of death', 'Her house is a path to shame', 'Her house leads to poverty and ruin', 'Her house brings a man to despair', 'a', 'Proverbs 7:27 says, "Her house is the way to hell, going down to the chambers of death."'),
('Proverbs', 7, 'adults', 1, 'What does Proverbs 7:2-3 instruct about keeping the father''s commandments?', 'Keep them as the apple of thine eye, bind them upon thy fingers, write them upon thine heart', 'Read them morning and evening', 'Teach them to thy children', 'Recite them before the LORD daily', 'a', 'Proverbs 7:2-3 says, "Keep my commandments, and live...bind them upon thy fingers, write them upon the table of thine heart."'),
('Proverbs', 7, 'adults', 2, 'How does Proverbs 7:13 describe the boldness of the strange woman?', 'She caught him, and kissed him, and with an impudent face said unto him', 'She called to him from her window', 'She sent a servant with a message', 'She waited quietly at her door', 'a', 'Proverbs 7:13 says, "So she caught him, and kissed him, and with an impudent face said unto him."'),
('Proverbs', 7, 'adults', 3, 'What religious activity does the strange woman use as a lure in Proverbs 7:14?', 'Peace offerings were due and she had paid her vows', 'She invited him to a feast at the temple', 'She claimed to have a prophecy for him', 'She said God had sent her to him', 'a', 'Proverbs 7:14 says, "I have peace offerings with me; this day have I payed my vows."'),
('Proverbs', 7, 'adults', 4, 'What three comparisons does Proverbs 7:22-23 use to describe the fate of the foolish young man?', 'An ox to slaughter, a fool to correction, a bird to a snare', 'A fish to the net, a moth to the flame, a dog to his vomit', 'A sheep to the fold, a child to punishment, a deer to the arrow', 'A lion to the trap, a fly to the web, a boar to the spear', 'a', 'Proverbs 7:22-23 says he goes "as an ox goeth to the slaughter...as a fool to the correction of the stocks; as a bird hasteth to the snare."'),
('Proverbs', 7, 'adults', 5, 'What does Proverbs 7:21 say the woman used to seduce the young man?', 'With her much fair speech she caused him to yield, with the flattering of her lips she forced him', 'With gifts and fine clothing', 'With promises of wealth', 'With tears and pleading', 'a', 'Proverbs 7:21 says, "With her much fair speech she caused him to yield, with the flattering of her lips she forced him."'),
('Proverbs', 7, 'adults', 6, 'What does the phrase "he knoweth not that it is for his life" in Proverbs 7:23 emphasise?', 'The deadly spiritual blindness of the man seduced by immorality', 'The speed at which sin overtakes a man', 'The certainty of divine punishment', 'The foolishness of ignoring wisdom''s warnings', 'a', '"He knoweth not that it is for his life" (Proverbs 7:23) shows the spiritually blinded man does not see he is walking to his own destruction.'),
('Proverbs', 7, 'adults', 7, 'What instruction does Proverbs 7:24-25 give after describing the seduction?', 'Hearken unto me, let not thine heart decline to her ways, go not astray in her paths', 'Flee from the city where she dwells', 'Warn thy brothers about her', 'Trust in the LORD for deliverance', 'a', 'Proverbs 7:24-25 says, "Hearken unto me now therefore...Let not thine heart decline to her ways, go not astray in her paths."'),
('Proverbs', 7, 'adults', 8, 'What does the strange woman''s preparation described in Proverbs 7:16-17 reveal about her seduction?', 'She has prepared her bed with fine linen and perfumed it with myrrh, aloes, and cinnamon', 'She has prepared a great feast', 'She has adorned herself in costly garments', 'She has cleared her house of her husband''s belongings', 'a', 'Proverbs 7:16-17 says, "I have decked my bed with coverings...I have perfumed my bed with myrrh, aloes, and cinnamon."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Proverbs', 8, 'kids', 1, 'In Proverbs 8, where does Wisdom stand to call out to people?', 'Upon the high places, at the gates, at the entry of the city', 'In the temple', 'By the river', 'In the marketplace', 'a', 'Proverbs 8:2-3 says, "She standeth in the top of high places...at the gates, at the entry of the city."'),
('Proverbs', 8, 'kids', 2, 'What does Proverbs 8 say wisdom is better than?', 'Rubies', 'Silver and gold', 'Fine clothing', 'Mighty armies', 'a', 'Proverbs 8:11 says, "For wisdom is better than rubies."'),
('Proverbs', 8, 'kids', 3, 'What does Proverbs 8:17 say wisdom does for those who love her?', 'She loves them that love her', 'She gives them great riches', 'She makes them kings', 'She teaches them all things', 'a', 'Proverbs 8:17 says, "I love them that love me; and those that seek me early shall find me."'),
('Proverbs', 8, 'teens', 1, 'What does Proverbs 8:13 say the fear of the LORD involves?', 'Hating evil, pride, arrogance, the evil way, and the froward mouth', 'Keeping all the commandments perfectly', 'Offering sacrifices daily at the temple', 'Fasting and praying without ceasing', 'a', 'Proverbs 8:13 says, "The fear of the LORD is to hate evil: pride, and arrogancy, and the evil way, and the froward mouth, do I hate."'),
('Proverbs', 8, 'teens', 2, 'What two qualities does wisdom dwell with according to Proverbs 8:12?', 'Prudence, and she finds out knowledge and discretion', 'Righteousness and peace', 'Strength and honour', 'Truth and mercy', 'a', 'Proverbs 8:12 says, "I wisdom dwell with prudence, and find out knowledge of witty inventions."'),
('Proverbs', 8, 'teens', 3, 'What does wisdom give to kings and princes according to Proverbs 8:15-16?', 'By me kings reign and princes decree justice', 'She gives them long reign and victory in battle', 'She fills their treasuries with silver', 'She causes all nations to honour them', 'a', 'Proverbs 8:15-16 says, "By me kings reign, and princes decree justice. By me princes rule, and nobles, even all the judges of the earth."'),
('Proverbs', 8, 'teens', 4, 'What was wisdom''s role at the time of creation according to Proverbs 8:30?', 'She was beside God as a master workman, daily his delight', 'She watched the creation from afar', 'She named the animals with Adam', 'She sang praises as God created', 'a', 'Proverbs 8:30 says, "Then I was by him, as one brought up with him: and I was daily his delight."'),
('Proverbs', 8, 'teens', 5, 'What does Proverbs 8:35-36 say about finding or missing wisdom?', 'Whoso findeth wisdom findeth life; he that sinneth against wisdom wrongeth his own soul', 'Wisdom rewards the faithful and punishes the wicked', 'Finding wisdom brings riches; missing it brings poverty', 'Wisdom welcomes the humble and rejects the proud', 'a', 'Proverbs 8:35-36 says, "For whoso findeth me findeth life...But he that sinneth against me wrongeth his own soul."'),
('Proverbs', 8, 'adults', 1, 'What does Proverbs 8:6-8 say about the words of wisdom?', 'They are excellent, right, true, and nothing froward or perverse', 'They are sweet and pleasant to the ear', 'They are sharper than a two-edged sword', 'They are preserved forever in the LORD''s memory', 'a', 'Proverbs 8:6-8 says, "Hear...excellent things...all the words of my mouth are in righteousness; there is nothing froward or perverse in them."'),
('Proverbs', 8, 'adults', 2, 'What does Proverbs 8:10-11 say wisdom is worth compared to choice silver?', 'Receive her instruction rather than silver; wisdom is better than rubies and all things desired not comparable', 'Wisdom can buy more than silver can', 'Wisdom brings silver as its reward', 'Both wisdom and silver are necessary', 'a', 'Proverbs 8:10-11 says, "Receive my instruction, and not silver...For wisdom is better than rubies; and all the things that may be desired are not to be compared to it."'),
('Proverbs', 8, 'adults', 3, 'In Proverbs 8:22-23, how does Wisdom describe her origin?', 'The LORD possessed me at the beginning of his work, before the earth was', 'I was created on the fourth day of creation', 'I sprang forth from the heart of God at the flood', 'I came into being when man first sought understanding', 'a', 'Proverbs 8:22-23 says, "The LORD possessed me at the beginning of his work, the first of his acts of old. I was set up from everlasting, from the beginning."'),
('Proverbs', 8, 'adults', 4, 'What does Proverbs 8:24-26 emphasise about wisdom''s pre-existence?', 'Wisdom was brought forth before the depths, hills, fields, and the dust of the world', 'Wisdom appeared at the same time as the angels', 'Wisdom was formed when the first man was created', 'Wisdom preceded the law given to Moses', 'a', 'Proverbs 8:24-26 says wisdom was brought forth before "the depths...before the mountains were settled...before he had made the earth."'),
('Proverbs', 8, 'adults', 5, 'What does wisdom say she hates in Proverbs 8:7?', 'Wickedness is an abomination to my lips', 'The ways of the violent man', 'The counsel of the froward', 'The proud and arrogant', 'a', 'Proverbs 8:7 says, "for my mouth shall speak truth; and wickedness is an abomination to my lips."'),
('Proverbs', 8, 'adults', 6, 'What does Proverbs 8:19 say wisdom''s fruit is better than?', 'Fine gold; her revenue better than choice silver', 'Honey from the rock', 'The finest offerings at the temple', 'Earthly power and fame', 'a', 'Proverbs 8:19 says, "My fruit is better than gold, yea, than fine gold; and my revenue than choice silver."'),
('Proverbs', 8, 'adults', 7, 'What does the theological concept of wisdom''s pre-existence in Proverbs 8 foreshadow in Christian interpretation?', 'The eternal Word of God, the Logos, identified as Christ in John 1', 'The law given on Sinai', 'The Spirit moving on the waters in Genesis 1', 'The angel of the LORD appearing to Abraham', 'a', 'The personification of wisdom in Proverbs 8 as present before creation is widely seen as prefiguring the eternal Logos — Christ — of John 1:1-3.'),
('Proverbs', 8, 'adults', 8, 'What does Proverbs 8:32-33 instruct those who have heard wisdom''s call?', 'Hearken unto me, hear instruction and be wise, refuse it not', 'Return to her daily as to a spring of water', 'Teach others what wisdom has taught thee', 'Seek wisdom even if the cost is great', 'a', 'Proverbs 8:32-33 says, "Now therefore hearken unto me...Hear instruction, and be wise, and refuse it not."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Proverbs', 9, 'kids', 1, 'How many pillars did Wisdom build in her house in Proverbs 9?', 'Seven pillars', 'Twelve pillars', 'Four pillars', 'Ten pillars', 'a', 'Proverbs 9:1 says, "Wisdom hath builded her house, she hath hewn out her seven pillars."'),
('Proverbs', 9, 'kids', 2, 'What does Proverbs 9:10 say is the beginning of wisdom?', 'The fear of the LORD', 'Love for God', 'Reading the law', 'Honouring parents', 'a', 'Proverbs 9:10 says, "The fear of the LORD is the beginning of wisdom."'),
('Proverbs', 9, 'kids', 3, 'What does Folly do in Proverbs 9?', 'She sits at the door of her house and calls to passers-by', 'She roams the streets looking for the simple', 'She stands at the city gate weeping', 'She hides in the darkness', 'a', 'Proverbs 9:14 says, "For she sitteth at the door of her house, on a seat in the high places of the city."'),
('Proverbs', 9, 'teens', 1, 'What did Wisdom do after building her house and preparing her feast in Proverbs 9?', 'She sent out her maidens and called from the high places of the city', 'She went personally to every home', 'She sent letters to the simple', 'She waited silently at her door', 'a', 'Proverbs 9:3 says, "She hath sent forth her maidens: she crieth upon the highest places of the city."'),
('Proverbs', 9, 'teens', 2, 'What does Proverbs 9:7-8 say about correcting a scorner?', 'He that reproveth a scorner getteth shame; reprove not a scorner lest he hate thee', 'A scorner will eventually respond to patience', 'A scorner should be avoided completely', 'A scorner needs public rebuke', 'a', 'Proverbs 9:7-8 says, "He that reproveth a scorner getteth to himself shame...reprove not a scorner, lest he hate thee."'),
('Proverbs', 9, 'teens', 3, 'What does Proverbs 9:9 promise if you give instruction to a wise man?', 'He will be yet wiser; teach a just man and he will increase in learning', 'He will teach it to others', 'He will honour thee above all men', 'He will return the favour doubly', 'a', 'Proverbs 9:9 says, "Give instruction to a wise man, and he will be yet wiser: teach a just man, and he will increase in learning."'),
('Proverbs', 9, 'teens', 4, 'What deceptive invitation does Folly make in Proverbs 9:17?', 'Stolen waters are sweet and bread eaten in secret is pleasant', 'Come in, for all is prepared for you', 'The wise man is wrong; my way is better', 'Leave wisdom and find true pleasure here', 'a', 'Proverbs 9:17 says, "Stolen waters are sweet, and bread eaten in secret is pleasant."'),
('Proverbs', 9, 'teens', 5, 'What does the guest of Folly not know in Proverbs 9:18?', 'That the dead are there and her guests are in the depths of hell', 'That she has stolen what she offers', 'That her house is built on sand', 'That the LORD watches their secret deeds', 'a', 'Proverbs 9:18 says, "But he knoweth not that the dead are there; and that her guests are in the depths of hell."'),
('Proverbs', 9, 'adults', 1, 'What does Wisdom''s feast in Proverbs 9:2-5 include, and what does she invite the simple to do?', 'She slew her beasts and mingled wine; she invites the simple to forsake foolishness and live', 'She prepared a great banquet for the righteous only', 'She offered bread and water to those who sought her', 'She invited kings and nobles to her table', 'a', 'Proverbs 9:2-4 says she prepared meat, mingled wine and says, "Come, eat of my bread, and drink of the wine which I have mingled."'),
('Proverbs', 9, 'adults', 2, 'What distinction does Proverbs 9:8 draw between a scorner and a wise man in how they receive rebuke?', 'Rebuke a wise man and he will love thee, but a scorner hates the reprover', 'The scorner argues while the wise man is silent', 'The scorner flees while the wise man stays', 'The scorner weeps while the wise man gives thanks', 'a', 'Proverbs 9:8 says, "Reprove not a scorner...rebuke a wise man, and he will love thee."'),
('Proverbs', 9, 'adults', 3, 'How does Proverbs 9:10 define true knowledge as distinct from the beginning of wisdom?', 'The knowledge of the holy is understanding', 'Wisdom leads to knowledge which leads to truth', 'Fear is wisdom, knowledge is its fruit', 'The holy Scriptures are the source of all knowledge', 'a', 'Proverbs 9:10 says, "The fear of the LORD is the beginning of wisdom: and the knowledge of the holy is understanding."'),
('Proverbs', 9, 'adults', 4, 'What personal benefit does Proverbs 9:12 assign to wisdom and scorn?', 'If thou art wise, thou art wise for thyself; if thou scornest, thou alone shalt bear it', 'Wisdom benefits your family; scorn harms your enemies', 'Wisdom enriches all around you; scorn impoverishes the fool only', 'Wisdom serves God; scorn serves no one', 'a', 'Proverbs 9:12 says, "If thou be wise, thou shalt be wise for thyself: but if thou scornest, thou alone shalt bear it."'),
('Proverbs', 9, 'adults', 5, 'What does Wisdom''s complete invitation in Proverbs 9:6 call the simple to do?', 'Forsake the foolish, and live; go in the way of understanding', 'Come to the feast and eat freely', 'Turn from all wickedness and follow her', 'Seek the LORD with all your heart', 'a', 'Proverbs 9:6 says, "Forsake the foolish, and live; and go in the way of understanding."'),
('Proverbs', 9, 'adults', 6, 'What does Proverbs 9:11 say wisdom does for the years of the seeker?', 'For by me thy days shall be multiplied, and the years of thy life shall be increased', 'She adds honour to all the years of thy life', 'She fills the years with understanding', 'She gives thee years of peace and rest', 'a', 'Proverbs 9:11 says, "For by me thy days shall be multiplied, and the years of thy life shall be increased."'),
('Proverbs', 9, 'adults', 7, 'What structural contrast does Proverbs 9 present between Wisdom''s house and Folly''s house?', 'Wisdom builds on seven pillars, slays beasts and mingles wine; Folly sits idle at her door with stolen water and secret bread', 'Wisdom''s house is on a hill; Folly''s house is in a valley', 'Wisdom''s house is open to all; Folly''s house is hidden', 'Wisdom''s house is ancient; Folly''s house is new', 'a', 'Proverbs 9:1-5 shows Wisdom building, preparing, and sending out; Proverbs 9:13-18 shows Folly sitting, calling, and offering only "stolen waters."'),
('Proverbs', 9, 'adults', 8, 'In Proverbs 9:13-16, who specifically does Folly target with her call?', 'Whoso is simple and him that wanteth understanding', 'The rich young ruler', 'The wise man who has strayed', 'The man who rejected Wisdom', 'a', 'Proverbs 9:16 says, "Whoso is simple, let him turn in hither: and as for him that wanteth understanding."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Proverbs', 10, 'kids', 1, 'What does Proverbs 10:1 say a wise son does for his father?', 'He maketh a glad father', 'He honoureth his father''s name', 'He enricheth his father''s house', 'He bringeth peace to his father', 'a', 'Proverbs 10:1 says, "A wise son maketh a glad father: but a foolish son is the heaviness of his mother."'),
('Proverbs', 10, 'kids', 2, 'What does Proverbs 10:12 say love does to sins?', 'Love covereth all sins', 'Love avoideth all sins', 'Love removeth all sins', 'Love punisheth all sins', 'a', 'Proverbs 10:12 says, "love covereth all sins."'),
('Proverbs', 10, 'kids', 3, 'What does Proverbs 10:7 say about the memory of the just?', 'The memory of the just is blessed', 'The memory of the just lasts forever', 'The memory of the just is treasured by God', 'The memory of the just comforts the living', 'a', 'Proverbs 10:7 says, "The memory of the just is blessed."'),
('Proverbs', 10, 'teens', 1, 'What contrast does Proverbs 10:4 draw about diligence and laziness?', 'He becometh poor that dealeth with a slack hand, but the hand of the diligent maketh rich', 'The lazy man sleeps while the diligent man prays', 'Laziness brings shame while diligence brings honour', 'The lazy man wastes time while the diligent man saves it', 'a', 'Proverbs 10:4 says, "He becometh poor that dealeth with a slack hand: but the hand of the diligent maketh rich."'),
('Proverbs', 10, 'teens', 2, 'What does Proverbs 10:9 say about the person who walks uprightly?', 'He that walketh uprightly walketh surely', 'His path is always plain before him', 'The LORD guides his every step', 'His enemies cannot touch him', 'a', 'Proverbs 10:9 says, "He that walketh uprightly walketh surely: but he that perverteth his ways shall be known."'),
('Proverbs', 10, 'teens', 3, 'What does Proverbs 10:19 teach about many words?', 'In the multitude of words there wanteth not sin; he that refraineth his lips is wise', 'Many words prove a man''s wisdom', 'The wise man speaks freely among friends', 'Words are measured by their quality not quantity', 'a', 'Proverbs 10:19 says, "In the multitude of words there wanteth not sin: but he that refraineth his lips is wise."'),
('Proverbs', 10, 'teens', 4, 'What does Proverbs 10:22 say about the blessing of the LORD?', 'The blessing of the LORD, it maketh rich, and he addeth no sorrow with it', 'The blessing of the LORD comes to those who seek him early', 'The blessing of the LORD is wisdom above all things', 'The blessing of the LORD is given freely to the humble', 'a', 'Proverbs 10:22 says, "The blessing of the LORD, it maketh rich, and he addeth no sorrow with it."'),
('Proverbs', 10, 'teens', 5, 'What does Proverbs 10:25 say about the righteous when a whirlwind passes?', 'The righteous is an everlasting foundation', 'The righteous bends but does not break', 'The righteous flees to safety', 'The righteous trusts and is not moved', 'a', 'Proverbs 10:25 says, "As the whirlwind passeth, so is the wicked no more: but the righteous is an everlasting foundation."'),
('Proverbs', 10, 'adults', 1, 'What does Proverbs 10:2 say about treasures of wickedness?', 'Treasures of wickedness profit nothing: but righteousness delivereth from death', 'Wicked treasure fades quickly', 'Stolen goods bring a curse', 'The LORD takes away what wickedness gathers', 'a', 'Proverbs 10:2 says, "Treasures of wickedness profit nothing: but righteousness delivereth from death."'),
('Proverbs', 10, 'adults', 2, 'What does Proverbs 10:11 say the mouth of the righteous is?', 'A well of life; but violence covereth the mouth of the wicked', 'A source of blessing to all who hear', 'A lamp that guideth others in darkness', 'A sword that cutteth down the wicked', 'a', 'Proverbs 10:11 says, "The mouth of a righteous man is a well of life: but violence covereth the mouth of the wicked."'),
('Proverbs', 10, 'adults', 3, 'What literary form characterises most proverbs in chapters 10-15 and what is it called?', 'Antithetical parallelism — two contrasting lines joined by "but"', 'Synonymous parallelism — two lines saying the same thing', 'Synthetic parallelism — two lines building on each other', 'Chiastic structure — mirror-image parallelism', 'a', 'Chapters 10-15 are dominated by antithetical proverbs where the second line contrasts the first with "but," e.g., Proverbs 10:1.'),
('Proverbs', 10, 'adults', 4, 'What does Proverbs 10:17 say about keeping instruction and refusing reproof?', 'He is in the way of life that keepeth instruction; he that refuseth reproof erreth', 'Keeping instruction brings wealth and refusing it brings poverty', 'Instruction leads to wisdom; refusing it leads to foolishness', 'The keeper of instruction is honoured; the refuser is forgotten', 'a', 'Proverbs 10:17 says, "He is in the way of life that keepeth instruction: but he that refuseth reproof erreth."'),
('Proverbs', 10, 'adults', 5, 'What does Proverbs 10:26 compare a lazy messenger to?', 'Vinegar to the teeth and smoke to the eyes', 'A broken wheel on a cart', 'A stone in a smooth path', 'A cloud without rain', 'a', 'Proverbs 10:26 says, "As vinegar to the teeth, and as smoke to the eyes, so is the sluggard to them that send him."'),
('Proverbs', 10, 'adults', 6, 'What does Proverbs 10:12 contrast with love covering sins?', 'Hatred stirreth up strifes', 'Envy destroys relationships', 'Folly reveals all shame', 'Pride multiplies offences', 'a', 'Proverbs 10:12 says, "Hatred stirreth up strifes: but love covereth all sins."'),
('Proverbs', 10, 'adults', 7, 'What does Proverbs 10:20 say the heart of the wicked is?', 'Little worth', 'Full of deceit', 'Dark as night', 'Empty as a broken vessel', 'a', 'Proverbs 10:20 says, "The tongue of the just is as choice silver: the heart of the wicked is little worth."'),
('Proverbs', 10, 'adults', 8, 'What does Proverbs 10:31-32 say about the mouth of the righteous versus the froward?', 'The mouth of the just bringeth forth wisdom; the froward tongue shall be cut out', 'The righteous speak truth while the froward speak lies', 'The just are heard by all while the froward are ignored', 'The righteous speak seldom but well; the froward speak often but poorly', 'a', 'Proverbs 10:31-32 says, "The mouth of the just bringeth forth wisdom...The lips of the righteous know what is acceptable: but the mouth of the wicked speaketh frowardness."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Proverbs', 11, 'kids', 1, 'What does Proverbs 11:2 say comes with pride?', 'Shame', 'Wealth', 'Loneliness', 'Sorrow', 'a', 'Proverbs 11:2 says, "When pride cometh, then cometh shame: but with the lowly is wisdom."'),
('Proverbs', 11, 'kids', 2, 'What does Proverbs 11:14 say a nation needs for safety?', 'A multitude of counsellors', 'A strong king', 'High walls and many soldiers', 'Wise judges', 'a', 'Proverbs 11:14 says, "but in the multitude of counsellors there is safety."'),
('Proverbs', 11, 'kids', 3, 'What does Proverbs 11:24 say about the generous person?', 'There is that scattereth, and yet increaseth', 'He who gives receives double in return', 'The generous man is loved by all', 'He who shares his bread will never go hungry', 'a', 'Proverbs 11:24 says, "There is that scattereth, and yet increaseth; and there is that withholdeth more than is meet, but it tendeth to poverty."'),
('Proverbs', 11, 'teens', 1, 'What does Proverbs 11:1 say the LORD abhors?', 'A false balance', 'A proud look', 'A lying tongue', 'A wicked heart', 'a', 'Proverbs 11:1 says, "A false balance is abomination to the LORD: but a just weight is his delight."'),
('Proverbs', 11, 'teens', 2, 'What does Proverbs 11:13 say about a talebearer?', 'A talebearer revealeth secrets; but he that is of a faithful spirit concealeth the matter', 'A talebearer is hated by all men', 'A talebearer brings division to families', 'A talebearer shall be punished by the elders', 'a', 'Proverbs 11:13 says, "A talebearer revealeth secrets: but he that is of a faithful spirit concealeth the matter."'),
('Proverbs', 11, 'teens', 3, 'What does Proverbs 11:17 say about a merciful man?', 'He doeth good to his own soul', 'He is rewarded with long life', 'He finds favour with God and men', 'He is protected from his enemies', 'a', 'Proverbs 11:17 says, "The merciful man doeth good to his own soul: but he that is cruel troubleth his own flesh."'),
('Proverbs', 11, 'teens', 4, 'What image does Proverbs 11:22 use for a beautiful woman without discretion?', 'A jewel of gold in a swine''s snout', 'A rose growing among thorns', 'A star that shines by day', 'A lamp left unguarded in the wind', 'a', 'Proverbs 11:22 says, "As a jewel of gold in a swine''s snout, so is a fair woman which is without discretion."'),
('Proverbs', 11, 'teens', 5, 'What does Proverbs 11:30 compare the fruit of the righteous to?', 'A tree of life', 'Choice silver', 'A flowing fountain', 'The morning light', 'a', 'Proverbs 11:30 says, "The fruit of the righteous is a tree of life; and he that winneth souls is wise."'),
('Proverbs', 11, 'adults', 1, 'What does Proverbs 11:3 say guides the upright versus what destroys the treacherous?', 'The integrity of the upright shall guide them, the perverseness of transgressors shall destroy them', 'Wisdom guides the upright; folly destroys the wicked', 'Truth guides the righteous; lies destroy the liar', 'The law guides the upright; sin destroys the transgressor', 'a', 'Proverbs 11:3 says, "The integrity of the upright shall guide them: but the perverseness of transgressors shall destroy them."'),
('Proverbs', 11, 'adults', 2, 'What does Proverbs 11:4 declare about riches in the day of wrath?', 'Riches profit not in the day of wrath: but righteousness delivereth from death', 'Riches can buy a little time but not salvation', 'The wicked man''s riches are taken away suddenly', 'A man''s wealth cannot follow him beyond the grave', 'a', 'Proverbs 11:4 says, "Riches profit not in the day of wrath: but righteousness delivereth from death."'),
('Proverbs', 11, 'adults', 3, 'What does Proverbs 11:9 say the hypocrite does with his mouth?', 'He destroyeth his neighbour', 'He deceiveth those who trust him', 'He spreadeth mischief through the city', 'He bringeth shame upon his family', 'a', 'Proverbs 11:9 says, "An hypocrite with his mouth destroyeth his neighbour: but through knowledge shall the just be delivered."'),
('Proverbs', 11, 'adults', 4, 'What does Proverbs 11:18 contrast about the wages of the wicked versus the righteous?', 'The wicked worketh a deceitful work, but he that soweth righteousness hath a sure reward', 'The wicked earn great wages now but lose all later', 'The wicked gain in secret while the righteous gain openly', 'The wicked''s wages perish while the righteous''s are stored up in heaven', 'a', 'Proverbs 11:18 says, "The wicked worketh a deceitful work: but to him that soweth righteousness shall be a sure reward."'),
('Proverbs', 11, 'adults', 5, 'What does Proverbs 11:25 say about the liberal soul?', 'The liberal soul shall be made fat; he that watereth shall be watered also himself', 'The generous man shall receive from the LORD', 'The open hand will never be empty', 'He who gives to the poor lends to the LORD', 'a', 'Proverbs 11:25 says, "The liberal soul shall be made fat: and he that watereth shall be watered also himself."'),
('Proverbs', 11, 'adults', 6, 'What does Proverbs 11:26 say about the man who withholds grain?', 'The people shall curse him', 'He shall be known as a miser', 'God shall judge his greed', 'He loses his blessing from above', 'a', 'Proverbs 11:26 says, "He that withholdeth corn, the people shall curse him: but blessing shall be upon the head of him that selleth it."'),
('Proverbs', 11, 'adults', 7, 'What does Proverbs 11:29 say about the one who troubleth his own house?', 'He shall inherit the wind', 'He shall be cast out of the city', 'He shall lose his inheritance', 'He shall come to poverty and shame', 'a', 'Proverbs 11:29 says, "He that troubleth his own house shall inherit the wind."'),
('Proverbs', 11, 'adults', 8, 'What does Proverbs 11:31 establish about the recompense of the righteous and sinner on earth?', 'Behold, the righteous shall be recompensed in the earth: much more the wicked and the sinner', 'God rewards the righteous in heaven and punishes the wicked on earth', 'The earth is a place of testing for all', 'Justice comes to all men before death', 'a', 'Proverbs 11:31 says, "Behold, the righteous shall be recompensed in the earth: much more the wicked and the sinner."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Proverbs', 12, 'kids', 1, 'What does Proverbs 12:1 say about loving instruction?', 'Whoso loveth instruction loveth knowledge', 'He who loves instruction will become wise', 'He who loves learning is loved by God', 'Loving instruction brings honour', 'a', 'Proverbs 12:1 says, "Whoso loveth instruction loveth knowledge: but he that hateth reproof is brutish."'),
('Proverbs', 12, 'kids', 2, 'What does Proverbs 12:10 say a righteous man does for animals?', 'He regardeth the life of his animal', 'He feeds his animal before himself', 'He trains his animal with kindness', 'He protects his animal from harm', 'a', 'Proverbs 12:10 says, "A righteous man regardeth the life of his animal."'),
('Proverbs', 12, 'kids', 3, 'What does Proverbs 12:17 say a true witness delivers?', 'Right things', 'Good news', 'Wise counsel', 'Just judgment', 'a', 'Proverbs 12:17 says, "An honest witness delivereth right things: but a deceitful witness speaketh lies." — "right" reflects truthful, upright testimony.'),
('Proverbs', 12, 'teens', 1, 'What does Proverbs 12:4 say a virtuous woman is to her husband?', 'A crown to her husband', 'His strength and honour', 'His joy and comfort', 'His wisdom and guide', 'a', 'Proverbs 12:4 says, "A virtuous woman is a crown to her husband."'),
('Proverbs', 12, 'teens', 2, 'What does Proverbs 12:11 say about one who follows vain persons?', 'He is void of understanding', 'He will come to poverty', 'He will lose his friends', 'He shall be ashamed among men', 'a', 'Proverbs 12:11 says, "but he that followeth vain persons is void of understanding."'),
('Proverbs', 12, 'teens', 3, 'What does Proverbs 12:15 say about a fool''s view of himself?', 'The way of a fool is right in his own eyes', 'A fool believes he is wiser than all', 'A fool never seeks instruction', 'A fool despises the counsel of the wise', 'a', 'Proverbs 12:15 says, "The way of a fool is right in his own eyes: but he that hearkeneth unto counsel is wise."'),
('Proverbs', 12, 'teens', 4, 'What does Proverbs 12:18 contrast about rash words and the tongue of the wise?', 'Speaking like piercings of a sword vs the tongue of the wise is health', 'Harsh words cut deep while kind words comfort', 'Rash words destroy while wise words build up', 'Foolish speech spreads pain while wisdom speaks sparingly', 'a', 'Proverbs 12:18 says, "There is that speaketh like the piercings of a sword: but the tongue of the wise is health."'),
('Proverbs', 12, 'teens', 5, 'What does Proverbs 12:24 say about the hand of the diligent?', 'The hand of the diligent shall bear rule', 'The diligent man shall not lack', 'The diligent hand is blessed of God', 'The diligent worker earns more than others', 'a', 'Proverbs 12:24 says, "The hand of the diligent shall bear rule: but the slothful shall be under tribute."'),
('Proverbs', 12, 'adults', 1, 'What does Proverbs 12:2 say about a man of wicked devices?', 'The LORD will condemn him', 'He shall fall by his own schemes', 'His wickedness shall be exposed', 'He gains the hatred of all men', 'a', 'Proverbs 12:2 says, "A good man obtaineth favour of the LORD: but a man of wicked devices will he condemn."'),
('Proverbs', 12, 'adults', 2, 'What does Proverbs 12:5 say the thoughts of the righteous are versus the counsels of the wicked?', 'The thoughts of the righteous are right; the counsels of the wicked are deceit', 'The righteous think deeply; the wicked act rashly', 'The righteous are transparent; the wicked are hidden', 'The righteous think of others; the wicked think of themselves', 'a', 'Proverbs 12:5 says, "The thoughts of the righteous are right: but the counsels of the wicked are deceit."'),
('Proverbs', 12, 'adults', 3, 'What does Proverbs 12:7 say about the house of the righteous versus the wicked being overthrown?', 'The wicked are overthrown and are not; but the house of the righteous shall stand', 'The wicked fall quickly while the righteous rise slowly', 'God pulls down the wicked''s house but builds the righteous''s', 'The wicked build on sand; the righteous on rock', 'a', 'Proverbs 12:7 says, "The wicked are overthrown, and are not: but the house of the righteous shall stand."'),
('Proverbs', 12, 'adults', 4, 'What does Proverbs 12:14 teach about the fruit of a man''s mouth?', 'A man shall be satisfied with good by the fruit of his mouth', 'A man''s speech reveals what is in his heart', 'A man''s words return to him in kind', 'A man''s lips either bless or curse him', 'a', 'Proverbs 12:14 says, "A man shall be satisfied with good by the fruit of his mouth."'),
('Proverbs', 12, 'adults', 5, 'What does Proverbs 12:19 promise about truthful lips versus a lying tongue?', 'Truthful lips shall be established for ever; a lying tongue is but for a moment', 'Truth is rewarded and lies are punished', 'The truth teller is trusted while the liar is shunned', 'God preserves the truthful word and destroys the false', 'a', 'Proverbs 12:19 says, "The lip of truth shall be established for ever: but a lying tongue is but for a moment."'),
('Proverbs', 12, 'adults', 6, 'What does Proverbs 12:20 say about the heart of those who imagine evil versus those who counsel peace?', 'Deceit is in the heart of them that imagine evil; joy to the counsellors of peace', 'Evil is hidden in the heart but joy is spoken aloud', 'The schemer finds no rest but the peacemaker finds rest', 'Deceit brings destruction and peace brings prosperity', 'a', 'Proverbs 12:20 says, "Deceit is in the heart of them that imagine evil: but to the counsellors of peace is joy."'),
('Proverbs', 12, 'adults', 7, 'What does Proverbs 12:25 say lifts up the spirit of a heavy-hearted man?', 'A good word maketh it glad', 'The comfort of friends restores the spirit', 'The LORD lifts the spirit of the sad', 'Prayer turns heaviness into joy', 'a', 'Proverbs 12:25 says, "Heaviness in the heart of man maketh it stoop: but a good word maketh it glad."'),
('Proverbs', 12, 'adults', 8, 'What does Proverbs 12:26 say the righteous is to his neighbour?', 'More excellent than his neighbour', 'A guide to the righteous path', 'A source of wisdom and strength', 'A shield in times of trouble', 'a', 'Proverbs 12:26 says, "The righteous is more excellent than his neighbour: but the way of the wicked seduceth them."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Proverbs', 13, 'kids', 1, 'What does Proverbs 13:20 say happens to those who walk with wise men?', 'They shall be wise', 'They shall become rich', 'They shall be honoured', 'They shall be protected', 'a', 'Proverbs 13:20 says, "He that walketh with wise men shall be wise."'),
('Proverbs', 13, 'kids', 2, 'What does Proverbs 13:24 say a parent who spares the rod does?', 'He hateth his son', 'He honoureth his son above God', 'He neglects his son''s training', 'He brings shame upon himself', 'a', 'Proverbs 13:24 says, "He that spareth his rod hateth his son."'),
('Proverbs', 13, 'kids', 3, 'What does Proverbs 13:3 say about guarding the mouth?', 'He that keepeth his mouth keepeth his life', 'A guarded mouth speaks only truth', 'The careful tongue avoids all sin', 'A wise child is slow to speak', 'a', 'Proverbs 13:3 says, "He that keepeth his mouth keepeth his life: but he that openeth wide his lips shall have destruction."'),
('Proverbs', 13, 'teens', 1, 'What does Proverbs 13:1 contrast about a wise son and a scorner?', 'A wise son heareth his father''s instruction but a scorner heareth not rebuke', 'A wise son prospers but a scorner fails', 'A wise son is loved but a scorner is despised', 'A wise son speaks carefully but a scorner speaks rashly', 'a', 'Proverbs 13:1 says, "A wise son heareth his father''s instruction: but a scorner heareth not rebuke."'),
('Proverbs', 13, 'teens', 2, 'What does Proverbs 13:7 observe about wealth and poverty?', 'There is that maketh himself rich, yet hath nothing; and that maketh himself poor, yet hath great riches', 'Riches deceive while poverty reveals character', 'The poor man may be richer in God''s sight', 'Wealth is not always what it appears to be', 'a', 'Proverbs 13:7 says, "There is that maketh himself rich, yet hath nothing: and there is that maketh himself poor, yet hath great riches."'),
('Proverbs', 13, 'teens', 3, 'What does Proverbs 13:11 say about wealth gotten by vanity?', 'It shall be diminished; but he that gathereth by labour shall increase', 'It brings no lasting satisfaction', 'It tempts a man into further sin', 'It brings judgment upon the house', 'a', 'Proverbs 13:11 says, "Wealth gotten by vanity shall be diminished: but he that gathereth by labour shall increase."'),
('Proverbs', 13, 'teens', 4, 'What does Proverbs 13:12 say about hope deferred?', 'Hope deferred maketh the heart sick: but when the desire cometh, it is a tree of life', 'Deferred hope is better than no hope at all', 'Waiting for hope tests the strength of the soul', 'A man without hope is lost', 'a', 'Proverbs 13:12 says, "Hope deferred maketh the heart sick: but when the desire cometh, it is a tree of life."'),
('Proverbs', 13, 'teens', 5, 'What does Proverbs 13:18 say about refusing instruction?', 'Poverty and shame shall be to him that refuseth instruction', 'He who rejects reproof will fall suddenly', 'A man without instruction makes poor decisions', 'Refusing instruction is the first step to ruin', 'a', 'Proverbs 13:18 says, "Poverty and shame shall be to him that refuseth instruction: but he that regardeth reproof shall be honoured."'),
('Proverbs', 13, 'adults', 1, 'What does Proverbs 13:4 say about the sluggard versus the diligent?', 'The soul of the sluggard desireth and hath nothing; the soul of the diligent shall be made fat', 'The lazy man wishes but the diligent man works', 'The sluggard dreams while the diligent man acts', 'Desiring without working leads to emptiness', 'a', 'Proverbs 13:4 says, "The soul of the sluggard desireth, and hath nothing: but the soul of the diligent shall be made fat."'),
('Proverbs', 13, 'adults', 2, 'What does Proverbs 13:9 contrast about the light of the righteous and the lamp of the wicked?', 'The light of the righteous rejoiceth; but the lamp of the wicked shall be put out', 'The righteous''s light grows brighter while the wicked''s dims', 'The righteous shine in darkness; the wicked cannot find their way', 'God tends the righteous''s lamp but not the wicked''s', 'a', 'Proverbs 13:9 says, "The light of the righteous rejoiceth: but the lamp of the wicked shall be put out."'),
('Proverbs', 13, 'adults', 3, 'What does Proverbs 13:10 say is the only source of contention?', 'Only by pride cometh contention', 'A quick temper is the root of all strife', 'Envy and jealousy breed contention', 'Folly creates strife among men', 'a', 'Proverbs 13:10 says, "Only by pride cometh contention: but with the well advised is wisdom."'),
('Proverbs', 13, 'adults', 4, 'What does Proverbs 13:13 say about despising the word?', 'Whoso despiseth the word shall be destroyed', 'He who ignores wisdom faces its consequences', 'The despiser of the word walks in darkness', 'Rejecting God''s word leads to spiritual death', 'a', 'Proverbs 13:13 says, "Whoso despiseth the word shall be destroyed: but he that feareth the commandment shall be rewarded."'),
('Proverbs', 13, 'adults', 5, 'What does Proverbs 13:15 say about the way of transgressors?', 'The way of transgressors is hard', 'Sinners walk a path of thorns', 'The wicked road leads nowhere good', 'Transgression makes every journey difficult', 'a', 'Proverbs 13:15 says, "Good understanding giveth favour: but the way of transgressors is hard."'),
('Proverbs', 13, 'adults', 6, 'What does Proverbs 13:17 say about a wicked versus a faithful messenger?', 'A wicked messenger falleth into mischief; but a faithful ambassador is health', 'A wicked messenger brings bad tidings; a faithful one brings good news', 'A lying messenger is punished; a truthful one is rewarded', 'A lazy messenger fails his master; a diligent one succeeds', 'a', 'Proverbs 13:17 says, "A wicked messenger falleth into mischief: but a faithful ambassador is health."'),
('Proverbs', 13, 'adults', 7, 'What does Proverbs 13:22 say about the inheritance of a good man versus the sinner''s wealth?', 'A good man leaveth an inheritance to his children''s children; the sinner''s wealth is laid up for the just', 'A righteous man builds wealth that lasts three generations', 'A good man stores up a spiritual inheritance', 'The wicked''s wealth is cursed and turns to nothing', 'a', 'Proverbs 13:22 says, "A good man leaveth an inheritance to his children''s children: and the wealth of the sinner is laid up for the just."'),
('Proverbs', 13, 'adults', 8, 'What does Proverbs 13:25 say about the difference in eating between the righteous and the wicked?', 'The righteous eateth to the satisfying of his soul; the belly of the wicked shall want', 'The righteous eat little but are satisfied; the wicked eat much and are never full', 'God provides for the righteous but withholds from the wicked', 'The righteous''s bread is blessed while the wicked''s is cursed', 'a', 'Proverbs 13:25 says, "The righteous eateth to the satisfying of his soul: but the belly of the wicked shall want."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Proverbs', 14, 'kids', 1, 'What does Proverbs 14:34 say righteousness does for a nation?', 'Exalteth a nation', 'Strengthens a nation', 'Protects a nation', 'Enriches a nation', 'a', 'Proverbs 14:34 says, "Righteousness exalteth a nation: but sin is a reproach to any people."'),
('Proverbs', 14, 'kids', 2, 'What does Proverbs 14:12 say about a way that seems right to a person?', 'The end thereof are the ways of death', 'It may lead to trouble', 'It may not be the best way', 'It still needs to be tested', 'a', 'Proverbs 14:12 says, "There is a way which seemeth right unto a man, but the end thereof are the ways of death."'),
('Proverbs', 14, 'kids', 3, 'Who does Proverbs 14:21 say is happy?', 'He that hath mercy on the poor', 'He who loves his neighbour', 'He who helps the weak', 'He who gives generously', 'a', 'Proverbs 14:21 says, "but he that hath mercy on the poor, happy is he."'),
('Proverbs', 14, 'teens', 1, 'What does Proverbs 14:1 contrast about a wise woman and a foolish one?', 'Every wise woman buildeth her house; but the foolish plucketh it down with her hands', 'A wise woman speaks carefully but a foolish one hastily', 'A wise woman is patient but a foolish one is rash', 'A wise woman saves but a foolish one wastes', 'a', 'Proverbs 14:1 says, "Every wise woman buildeth her house: but the foolish plucketh it down with her hands."'),
('Proverbs', 14, 'teens', 2, 'What does Proverbs 14:10 say about the bitterness of the heart?', 'The heart knoweth his own bitterness; and a stranger doth not intermeddle with his joy', 'The heart that is bitter cannot receive joy', 'Deep pain is known only to God and oneself', 'A bitter heart cannot find peace', 'a', 'Proverbs 14:10 says, "The heart knoweth his own bitterness; and a stranger doth not intermeddle with his joy."'),
('Proverbs', 14, 'teens', 3, 'What does Proverbs 14:13 say about laughter?', 'Even in laughter the heart is sorrowful; and the end of that mirth is heaviness', 'Laughter is the medicine of the soul', 'A laughing man hides his true feelings', 'Joy without truth is empty and fleeting', 'a', 'Proverbs 14:13 says, "Even in laughter the heart is sorrowful; and the end of that mirth is heaviness."'),
('Proverbs', 14, 'teens', 4, 'What does Proverbs 14:17 say about a quick-tempered man?', 'He that is soon angry dealeth foolishly', 'A hot-tempered man invites trouble', 'Anger without cause is a sin', 'A quick temper reveals a foolish heart', 'a', 'Proverbs 14:17 says, "He that is soon angry dealeth foolishly: and a man of wicked devices is hated."'),
('Proverbs', 14, 'teens', 5, 'What does Proverbs 14:30 contrast about envy and a sound heart?', 'A sound heart is the life of the flesh; but envy the rottenness of the bones', 'A sound heart brings peace; envy brings strife', 'Contentment gives life; envy destroys it', 'A peaceful heart is a blessing; envy is a curse', 'a', 'Proverbs 14:30 says, "A sound heart is the life of the flesh: but envy the rottenness of the bones."'),
('Proverbs', 14, 'adults', 1, 'What does Proverbs 14:4 say about where no oxen are?', 'The crib is clean: but much increase is by the strength of the ox', 'There is no ploughing and no harvest', 'The barn is empty and the farmer is poor', 'The field lies fallow and the work is not done', 'a', 'Proverbs 14:4 says, "Where no oxen are, the crib is clean: but much increase is by the strength of the ox."'),
('Proverbs', 14, 'adults', 2, 'What does Proverbs 14:6 say about the scorner and wisdom?', 'A scorner seeketh wisdom and findeth it not; but knowledge is easy unto him that understandeth', 'The scorner cannot receive what he mocks', 'Wisdom is hidden from the proud heart', 'He who despises truth will never find it', 'a', 'Proverbs 14:6 says, "A scorner seeketh wisdom, and findeth it not: but knowledge is easy unto him that understandeth."'),
('Proverbs', 14, 'adults', 3, 'What does Proverbs 14:20 reveal about social attitudes toward the poor and the rich?', 'The poor is hated even of his own neighbour; but the rich hath many friends', 'Society judges a man by his wealth', 'Poverty brings rejection while wealth brings false friends', 'Men court the rich but abandon the poor', 'a', 'Proverbs 14:20 says, "The poor is hated even of his own neighbour: but the rich hath many friends."'),
('Proverbs', 14, 'adults', 4, 'What does Proverbs 14:23 say about talk without labour?', 'In all labour there is profit; but the talk of the lips tendeth only to penury', 'Empty speech wastes the day', 'A man who only talks will come to nothing', 'Speaking without acting is the way of the sluggard', 'a', 'Proverbs 14:23 says, "In all labour there is profit: but the talk of the lips tendeth only to penury."'),
('Proverbs', 14, 'adults', 5, 'What does Proverbs 14:26-27 say about the fear of the LORD?', 'In the fear of the LORD is strong confidence; it is a fountain of life, to depart from the snares of death', 'The fear of the LORD gives strength in old age', 'Those who fear the LORD will never be put to shame', 'The fear of the LORD is the foundation of all virtue', 'a', 'Proverbs 14:26-27 says, "In the fear of the LORD is strong confidence...The fear of the LORD is a fountain of life, to depart from the snares of death."'),
('Proverbs', 14, 'adults', 6, 'What does Proverbs 14:29 contrast about a slow and hasty spirit?', 'He that is slow to wrath is of great understanding; but he that is hasty of spirit exalteth folly', 'Patience is strength; haste is weakness', 'The slow temper earns respect; the hot temper earns shame', 'Anger controlled is wisdom; anger uncontrolled is foolishness', 'a', 'Proverbs 14:29 says, "He that is slow to wrath is of great understanding: but he that is hasty of spirit exalteth folly."'),
('Proverbs', 14, 'adults', 7, 'What does Proverbs 14:31 say about oppressing the poor?', 'He that oppresseth the poor reproacheth his Maker', 'Oppressing the poor is an abomination to God', 'The oppressor of the poor will answer to God', 'He who harms the poor sins against heaven', 'a', 'Proverbs 14:31 says, "He that oppresseth the poor reproacheth his Maker: but he that honoureth him hath mercy on the poor."'),
('Proverbs', 14, 'adults', 8, 'What does Proverbs 14:35 say about the king and his servants?', 'The king''s favour is toward a wise servant: but his wrath is against him that causeth shame', 'A king rewards those who bring him good news', 'The king judges all men by their words', 'A servant who pleases the king gains great honour', 'a', 'Proverbs 14:35 says, "The king''s favour is toward a wise servant: but his wrath is against him that causeth shame."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Proverbs', 15, 'kids', 1, 'What does Proverbs 15:1 say a soft answer turns away?', 'Wrath', 'Danger', 'Foolishness', 'Sorrow', 'a', 'Proverbs 15:1 says, "A soft answer turneth away wrath."'),
('Proverbs', 15, 'kids', 2, 'What does Proverbs 15:3 say about the eyes of the LORD?', 'They are in every place, beholding the evil and the good', 'They see every secret thing', 'They watch over the righteous always', 'They never close and never sleep', 'a', 'Proverbs 15:3 says, "The eyes of the LORD are in every place, beholding the evil and the good."'),
('Proverbs', 15, 'kids', 3, 'What does Proverbs 15:17 say is better than a stalled ox with hatred?', 'A dinner of herbs where love is', 'A small meal shared with friends', 'Plain bread eaten in peace', 'A simple life without conflict', 'a', 'Proverbs 15:17 says, "Better is a dinner of herbs where love is, than a stalled ox and hatred therewith."'),
('Proverbs', 15, 'teens', 1, 'What does Proverbs 15:1 contrast with a soft answer?', 'A grievous word stirreth up anger', 'A harsh tone creates conflict', 'A loud voice increases anger', 'A proud reply makes things worse', 'a', 'Proverbs 15:1 says, "A soft answer turneth away wrath: but grievous words stir up anger."'),
('Proverbs', 15, 'teens', 2, 'What does Proverbs 15:8 say about the prayer of the upright?', 'It is his delight', 'It is heard immediately', 'It rises before God', 'It is answered in full', 'a', 'Proverbs 15:8 says, "but the prayer of the upright is his delight."'),
('Proverbs', 15, 'teens', 3, 'What does Proverbs 15:13 say a merry heart does?', 'It maketh a cheerful countenance', 'It bringeth joy to others', 'It lifts up the spirit', 'It is a gift from God', 'a', 'Proverbs 15:13 says, "A merry heart maketh a cheerful countenance: but by sorrow of the heart the spirit is broken."'),
('Proverbs', 15, 'teens', 4, 'What does Proverbs 15:22 say about plans made without counsel?', 'Without counsel purposes are disappointed', 'Plans made alone often fail', 'The man who consults no one is a fool', 'A plan without prayer is doomed to fail', 'a', 'Proverbs 15:22 says, "Without counsel purposes are disappointed: but in the multitude of counsellors they are established."'),
('Proverbs', 15, 'teens', 5, 'What does Proverbs 15:29 say about the LORD and the wicked versus the righteous?', 'The LORD is far from the wicked; but he heareth the prayer of the righteous', 'The LORD judges the wicked but saves the righteous', 'The LORD sees the wicked and punishes them', 'The LORD turns away from the wicked but draws near the righteous', 'a', 'Proverbs 15:29 says, "The LORD is far from the wicked: but he heareth the prayer of the righteous."'),
('Proverbs', 15, 'adults', 1, 'What does Proverbs 15:4 contrast about a wholesome tongue and a perverse one?', 'A wholesome tongue is a tree of life; but perverseness therein is a breach in the spirit', 'A wholesome tongue heals; a perverse one harms', 'Kind words build up; cruel words tear down', 'A good tongue brings blessing; a wicked one brings a curse', 'a', 'Proverbs 15:4 says, "A wholesome tongue is a tree of life: but perverseness therein is a breach in the spirit."'),
('Proverbs', 15, 'adults', 2, 'What does Proverbs 15:11 say about Hell and Destruction before the LORD?', 'Hell and destruction are before the LORD; how much more then the hearts of the children of men', 'Even the depths of hell are visible to God', 'No secret place is hidden from the LORD', 'God sees beyond the grave into eternity', 'a', 'Proverbs 15:11 says, "Hell and destruction are before the LORD: how much more then the hearts of the children of men?"'),
('Proverbs', 15, 'adults', 3, 'What does Proverbs 15:14 say the heart of the discerning seeks versus what the fool feeds on?', 'The heart of him that hath understanding seeketh knowledge; the mouth of fools feedeth on foolishness', 'The wise man hungers for wisdom; the fool is content with nothing', 'An understanding heart digs deep; a foolish heart stays shallow', 'The discerning seek to learn; the foolish seek only to speak', 'a', 'Proverbs 15:14 says, "The heart of him that hath understanding seeketh knowledge: but the mouth of fools feedeth on foolishness."'),
('Proverbs', 15, 'adults', 4, 'What does Proverbs 15:15 say about the cheerful heart versus the afflicted?', 'All the days of the afflicted are evil; but he that is of a merry heart hath a continual feast', 'The sad man sees only trouble; the happy man sees only good', 'Affliction clouds every day; joy brightens every one', 'The sorrowful live in shadow while the joyful live in light', 'a', 'Proverbs 15:15 says, "All the days of the afflicted are evil: but he that is of a merry heart hath a continual feast."'),
('Proverbs', 15, 'adults', 5, 'What does Proverbs 15:16-17 say is better than great treasure and a stalled ox?', 'Better is little with the fear of the LORD than great treasure and trouble; better a dinner of herbs where love is', 'A simple life of godliness exceeds wealth filled with anxiety', 'Peace with God is worth more than earthly prosperity', 'Contentment surpasses abundance without righteousness', 'a', 'Proverbs 15:16-17 says, "Better is little with the fear of the LORD than great treasure and trouble therewith. Better is a dinner of herbs where love is."'),
('Proverbs', 15, 'adults', 6, 'What does Proverbs 15:23 say about an apt word spoken in due season?', 'A word spoken in due season, how good is it', 'A timely word has power to heal a broken heart', 'Speaking at the right time brings the greatest result', 'A well-timed word is a rare and precious gift', 'a', 'Proverbs 15:23 says, "A man hath joy by the answer of his mouth: and a word spoken in due season, how good is it!"'),
('Proverbs', 15, 'adults', 7, 'What does Proverbs 15:25 say about the proud man''s house versus the widow?', 'The LORD will destroy the house of the proud; but he will establish the border of the widow', 'Pride brings a family to ruin while humility sustains it', 'God tears down arrogance and builds up the helpless', 'The proud man''s house falls; the humble man''s house stands', 'a', 'Proverbs 15:25 says, "The LORD will destroy the house of the proud: but he will establish the border of the widow."'),
('Proverbs', 15, 'adults', 8, 'What does Proverbs 15:33 say wisdom''s instruction is and what must come before honour?', 'The instruction of wisdom is the fear of the LORD; and before honour is humility', 'Wisdom leads to honour and honour leads to lasting reputation', 'Fear of God teaches all true wisdom and produces genuine honour', 'The path to honour is paved with wisdom''s hard lessons', 'a', 'Proverbs 15:33 says, "The fear of the LORD is the instruction of wisdom; and before honour is humility."');
